import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import orderService from '../../services/orderService';
import authService from '../../services/authService';
import { getMissingProfileFields, getProfileCompletion, normalizeProfile } from '../../utils/profileCompletion';

export default function DashboardProfile() {
    const { user, updateProfile } = useAuth();
    const [formData, setFormData] = useState(() => normalizeProfile(user));
    const [saving, setSaving] = useState(false);
    const [notice, setNotice] = useState('');
    const [error, setError] = useState('');
    const [totalOrders, setTotalOrders] = useState(0);
    const [avatarFile, setAvatarFile] = useState(null);
    const [avatarPreview, setAvatarPreview] = useState(() => user?.avatar_url || '');
    const avatarInputRef = useRef(null);

    const decodeTokenEmail = () => {
        try {
            const token = localStorage.getItem('auth_token');
            if (!token) {
                return '';
            }

            const payloadPart = token.split('.')[1] || '';
            if (!payloadPart) {
                return '';
            }

            const normalized = payloadPart.replace(/-/g, '+').replace(/_/g, '/');
            const padded = normalized + '='.repeat((4 - (normalized.length % 4)) % 4);
            const decoded = JSON.parse(window.atob(padded));
            return decoded?.email || decoded?.sub || '';
        } catch {
            return '';
        }
    };

    const displayEmail = user?.email
        || user?.customer_info?.email
        || formData.email
        || (() => {
            try {
                const cached = localStorage.getItem('auth_user');
                return cached ? (JSON.parse(cached)?.email || '') : '';
            } catch {
                return '';
            }
        })()
        || decodeTokenEmail();

    useEffect(() => {
        setFormData(normalizeProfile(user));
    }, [user]);

    useEffect(() => {
        setAvatarPreview(user?.avatar_url || '');
        setAvatarFile(null);
    }, [user]);

    const completion = useMemo(() => getProfileCompletion(formData), [formData]);
    const missing = useMemo(() => getMissingProfileFields(formData), [formData]);
    const initials = useMemo(() => {
        return (formData.name || user?.name || 'U')
            .split(' ')
            .filter(Boolean)
            .slice(0, 2)
            .map((part) => part[0]?.toUpperCase())
            .join('') || 'U';
    }, [formData.name, user?.name]);
    const memberSince = useMemo(() => {
        const raw = user?.created_at;
        const date = raw ? new Date(raw) : new Date();
        return Number.isNaN(date.getTime()) ? new Date().getFullYear() : date.getFullYear();
    }, [user]);

    useEffect(() => {
        let active = true;

        const loadOrderStats = async () => {
            try {
                const res = await orderService.getOrders({ page: 1 });
                if (!active) {
                    return;
                }

                const total = Number(res?.data?.data?.total ?? 0);
                setTotalOrders(Number.isFinite(total) ? total : 0);
            } catch {
                if (active) {
                    setTotalOrders(0);
                }
            }
        };

        loadOrderStats();

        return () => {
            active = false;
        };
    }, []);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
        setError('');
        setNotice('');
    };

    const handleAvatarChange = (e) => {
        const file = e.target.files?.[0];
        if (!file) {
            return;
        }

        setAvatarFile(file);
        setAvatarPreview(URL.createObjectURL(file));
        setError('');
        setNotice('');
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setSaving(true);
        setError('');
        setNotice('');

        try {
            const normalizedAddress = (formData.address || '').trim();

            if (avatarFile) {
                await authService.uploadAvatar(avatarFile);
            }

            const payload = {
                name: formData.name,
                phone: formData.phone,
                city: formData.city,
                region: formData.region,
                postal_code: formData.postal_code,
                address: normalizedAddress,
            };

            await updateProfile(payload);
            setNotice('Profile saved successfully.');
        } catch (err) {
            const apiMessage = err?.response?.data?.message;
            const timeout = err?.code === 'ECONNABORTED';
            const network = err?.message && String(err.message).toLowerCase().includes('network');

            if (apiMessage) {
                setError(apiMessage);
            } else if (timeout) {
                setError('Saving is taking too long. Please check your connection and try again.');
            } else if (network) {
                setError('Network issue while saving profile. Please try again.');
            } else {
                setError('Unable to save profile right now.');
            }
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="dashboard-grid dashboard-grid--profile">
            <section className="dashboard-panel profile-settings-panel">
                <h2>Personal Information</h2>

                {error && <div className="alert alert-danger">{error}</div>}
                {notice && <div className="alert alert-success">{notice}</div>}

                <div className="profile-avatar-uploader">
                    <div className="profile-avatar-preview">
                        {avatarPreview ? <img src={avatarPreview} alt="Profile" /> : <span>{initials}</span>}
                    </div>
                    <div className="profile-avatar-controls">
                        <button
                            type="button"
                            className="btn btn-outline-primary btn-sm"
                            onClick={() => avatarInputRef.current?.click()}
                        >
                            Upload Photo
                        </button>
                        <input
                            id="avatar"
                            ref={avatarInputRef}
                            type="file"
                            accept="image/*"
                            onChange={handleAvatarChange}
                            disabled={saving}
                            style={{ display: 'none' }}
                        />
                    </div>
                </div>

                <form className="profile-form-simple" onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label htmlFor="name">Full Name</label>
                        <input id="name" name="name" value={formData.name || ''} onChange={handleChange} required disabled={saving} />
                    </div>

                    <div className="form-group">
                        <label htmlFor="email">Logged-in Email</label>
                        <div className="profile-readonly-field">
                            <strong>{displayEmail || 'N/A'}</strong>
                            <span>Signed in account email</span>
                        </div>
                    </div>

                    <div className="form-group">
                        <label htmlFor="phone">Phone Number</label>
                        <input id="phone" name="phone" value={formData.phone || ''} onChange={handleChange} disabled={saving} />
                    </div>

                    <div className="form-group">
                        <label htmlFor="address">Address</label>
                        <input
                            id="address"
                            name="address"
                            value={formData.address || ''}
                            onChange={handleChange}
                            disabled={saving}
                            placeholder="Enter your full address"
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="city">City</label>
                        <input
                            id="city"
                            name="city"
                            value={formData.city || ''}
                            onChange={handleChange}
                            disabled={saving}
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="postal_code">Postal Code</label>
                        <input
                            id="postal_code"
                            name="postal_code"
                            value={formData.postal_code || ''}
                            onChange={handleChange}
                            disabled={saving}
                        />
                    </div>

                    <div className="profile-actions-row">
                        <button type="submit" className="btn btn-primary" disabled={saving}>
                            {saving ? 'Saving...' : 'Save Changes'}
                        </button>
                        <Link to="/dashboard/orders" className="btn btn-outline-primary">
                            View Orders
                        </Link>
                    </div>
                </form>
            </section>

            <section className="dashboard-panel profile-stats-panel">
                <h2>Account Statistics</h2>
                <div className="profile-stat-grid">
                    <article className="profile-stat-card">
                        <p>Member Since</p>
                        <strong>{memberSince}</strong>
                    </article>
                    <article className="profile-stat-card">
                        <p>Total Orders</p>
                        <strong>{totalOrders}</strong>
                    </article>
                    <article className="profile-stat-card">
                        <p>Profile Completion</p>
                        <strong>{completion}%</strong>
                        {missing.length > 0 && <span>{missing.length} missing field(s)</span>}
                    </article>
                </div>
            </section>
        </div>
    );
}
