import api from './api';
import { AxiosRequestConfig, AxiosPromise } from 'axios';

export type PaymentMethodType = 'cod' | 'gcash' | 'card' | 'bank_transfer';

interface OrderFiltersParams {
    status?: string;
    page?: number;
    per_page?: number;
    [key: string]: any;
}

interface OrderCreatePayload {
    items?: Array<{
        product_id: number;
        quantity: number;
    }>;
    payment_method: PaymentMethodType;
    shipping_address: string;
    notes?: string;
    payment_details?: {
        method?: string;
        account_name?: string;
        mobile_number?: string;
        reference_number?: string;
        bank_name?: string;
        cardholder_name?: string;
        card_last4?: string;
        expiry?: string;
    };
}

interface PaymentStatusPayload {
    status: string;
    transaction_id?: string;
}

export const orderService = {
    getOrders: (params?: OrderFiltersParams, config?: AxiosRequestConfig): AxiosPromise => 
        api.get('/orders', { params, ...config }),
    
    getOrderById: (id: string | number, config?: AxiosRequestConfig): AxiosPromise => 
        api.get(`/orders/${id}`, config),
    
    getOrder: (id: string | number, config?: AxiosRequestConfig): AxiosPromise => 
        api.get(`/orders/${id}`, config),
    
    createOrder: (data: OrderCreatePayload, config?: AxiosRequestConfig): AxiosPromise => 
        api.post('/orders', data, { timeout: 12000, ...config }),
    
    cancelOrder: (id: string | number, config?: AxiosRequestConfig): AxiosPromise => 
        api.patch(`/orders/${id}/cancel`, {}, config),
    
    updatePaymentStatus: (id: string | number, data: PaymentStatusPayload, config?: AxiosRequestConfig): AxiosPromise => 
        api.patch(`/orders/${id}/payment-status`, data, config),
};

export default orderService;
